CREATE PROC [dbo].[CREATE_CDNUR] @FromDate datetime, @ToDate datetime AS DECLARE @GSTIN AS CHAR(16) DECLARE @HSNCODETablename AS CHAR(16) DECLARE @HSNCodeField AS CHAR(12) DECLARE @IMTableQry AS VARCHAR(500) DECLARE @GSTIMPLDATE as Datetime IF OBJECT_ID('dbo.CDNUR','U') IS NOT NULL DROP TABLE CDNUR IF OBJECT_ID('dbo.CDNUR_Info','U') IS NOT NULL DROP TABLE CDNUR_Info SELECT @GSTIN=Txt FROM SysParam WHERE ParamCode='LocalSTaxRegnNo' Select @GSTIMPLDATE = dt from SysParam where ParamCode = 'GSTImplementationDate' SELECT * INTO CDNUR FROM ( SELECT 'B2CL' as [UR Type],STD.DocNoPrefix + '/' + CONVERT(VARCHAR(6),STD.DocNo) AS 'Note/Refund Voucher Number',STD.DocDt AS 'Note/Refund Voucher date','C' AS 'DocumentType',STHBkREf.DocNoPrefix + '/' + CONVERT(VARCHAR(6),STHBkREf.DocNo) AS 'Invoice/Advance Receipt Number',STHBkREf.DocDt AS 'Invoice/Advance Receipt date','Sales Return' AS 'Reason For Issuing document', Cast(Left(isnull(CUST.LSTNo,''),2) as Varchar(64)) AS [Place of Supply],sum(STH.NetDocValue) AS [Note/Refund Voucher Value],CAST(STD.stdTaxComp1Per AS Decimal(10,2))  AS 'Rate',CAST(SUM(STD.TaxAV1) AS Decimal(10,2)) AS 'Taxable Value', CAST(SUM(STD.TaxComp2)AS Decimal(10,2))  AS 'CESS Amount' ,CASE WHEN STHBkREf.DocDt < @GSTIMPLDATE then 'Y' ELSE 'N' END AS 'Pre GST' FROM StktrnDtls STD Inner Join StkTrnHdr STH  ON STH.TrnType=STD.TrnType AND STH.TrnCtrlNo=STD.TrnCtrlNo Inner JOin Customers CUST ON Cust.Code=STH.PartyID Inner JOIN StktrnHdr STHBkREf ON STHBkREf.TrnType=STD.BackRefTrnType AND STHBkREf.TrnCtrlNo= STD.BackRefCtrlNo WHERE (ISNULL(CUST.LSTNO,'')='' or len(CUST.LSTNO) < 6) AND (STH.TrnType=1300 ) AND STD.DocDt>=@FromDate AND STD.DocDt<=@ToDate AND STD.DocDt>=@GSTIMPLDATE AND STD.CustTaxType <> '0' AND STH.NetDocValue> 250000 GROUP BY STD.DocNoPrefix , STD.DocNo, STD.DocDt, STD.stdTaxComp1Per, CUST.LSTNo, STHBkREf.DocNoPrefix ,STHBkREf.DocNo ,STHBkREf.DocDt ) AS CDNRTempTable UPDATE  CD set [Place of Supply] = Cast([Place of Supply] as Varchar(4)) + '-' + GL.Descr FROM CDNUR CD Inner JOIN (SELECT Code,DEscr FROM GenLookUp WHERE RecID=92 ) GL on CD.[Place of Supply] = GL.Code SELECT COUNT(DISTINCT [Note/Refund Voucher Number]) AS [No. Of Notes/Vouchers], COUNT(DISTINCT [Invoice/Advance Receipt Number]) AS [No. of Invoices], SUM([Note/Refund Voucher Value]) AS [Total Note Value], SUM([Taxable Value]) AS [Total Taxable value], SUM([CESS AMOUNT]) AS [Total Cess]  INTO CDNUR_Info FROM CDNUR IF OBJECT_ID('CDNUR_Header','U') IS NULL CREATE TABLE CDNUR_Header ([Summary For CDNUR(9B)] Char(1) )INSERT INTO InfoTable Values('CDNUR',2,'<<Default>>','CDNUR',5) 